  ['DNA', 'evolution', 'DNA'],
  ['evolution', 'DNA'],
  ['parsing', 'phonology', 'parsing'],
  ['phonology', 'parsing'],
  ['DNA', 'evolution', 'evolution'],
  ['parsing', 'phonology']
];

